## Code Example

```javascript
const redact = (text) => {
  const emails = /[\w.+-]+@[\w.-]+\.[a-zA-Z]{2,}/g;
  const phones = /(\+?\d[\d\s\-\(\)]{7,}\d)/g;
  let out = text.replace(emails, "[REDACTED_EMAIL]");
  out = out.replace(phones, "[REDACTED_PHONE]");
  out = out.replace(/\b[A-Z][a-z]+ [A-Z][a-z]+\b/g, "[REDACTED_NAME]");
  return out;
}
```

