// Minimal in-browser inference
function hashWord(w) {
  let h = 0;
  for (let i = 0; i < w.length; i++) {
    h = (h * 31 + w.charCodeAt(i)) | 0;
  }
  return Math.abs(h);
}

function predict(text, weights, bias, numBuckets = 2048) {
  const features = new Array(numBuckets).fill(0);
  const words = text.toLowerCase().split(/\s+/);
  for (const word of words) {
    const idx = hashWord(word) % numBuckets;
    features[idx] += 1;
  }
  let score = bias;
  for (let i = 0; i < numBuckets; i++) {
    score += features[i] * weights[i];
  }
  return score > 0 ? 'positive' : 'negative';
}
```

