// Pseudocode: secure gradient aggregation with differential privacy
function aggregateGradients(partialGradients, noiseScale, clipThreshold) {
  // Clip each gradient to prevent individual influence
  const clipped = partialGradients.map(g => clipGradient(g, clipThreshold));

  // Add Gaussian noise for differential privacy
  const privateGradients = clipped.map(g => addNoise(g, noiseScale));

  // Secure aggregation across participants
  return secureAggregate(privateGradients);
}

function clipGradient(gradient, threshold) {
  const norm = Math.sqrt(gradient.reduce((sum, v) => sum + v * v, 0));
  if (norm > threshold) {
    return gradient.map(v => v * (threshold / norm));
  }
  return gradient;
}
```

