// Federated averaging sketch (simplified)
function aggregate(updates) {
  let totalN = updates.reduce((a, u) => a + u.n, 0);
  const dim = updates[0].weights.length;
  const sum = new Array(dim).fill(0);
  for (const u of updates) {
    for (let i = 0; i < dim; i++) sum[i] += u.weights[i] * u.n;
  }
  return sum.map(v => v / totalN);
}
```

