function scoreEscalation(messages, tfliteInterpreter) {
  const input = preprocessMessages(messages); // normalize, tokenize
  tfliteInterpreter.setInput(input);
  tfliteInterpreter.invoke();
  const output = tfliteInterpreter.output(0);
  return { score: output[0], threshold: 0.7 }; // escalate if above threshold
}

function checkRules(messages) {
  const urgentPatterns = [/\bhelp\b/i, /\burgent\b/i, /speak.*human/i];
  const urgentEmojis = ['🚨', '🙋', '😡', '😭'];
  const text = messages.join(' ');
  if (urgentPatterns.some(p => p.test(text)) || urgentEmojis.some(e => text.includes(e))) {
    return { escalate: true, confidence: 0.95, source: 'rule' };
  }
  return null;
}
